import React, { useState, useEffect } from 'react';
import { fetchTournaments, joinTournament } from '../utils/typingApi';
import '../styles/Tournaments.css';

export default function Tournaments() {
  const [tournaments, setTournaments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');
  const [joinedTournaments, setJoinedTournaments] = useState(new Set());
  const [processingId, setProcessingId] = useState(null);
  const [joinNotice, setJoinNotice] = useState(null);

  useEffect(() => {
    const loadTournaments = async () => {
      setLoading(true);
      const data = await fetchTournaments();
      setTournaments(data);
      setLoading(false);
    };
    loadTournaments();
  }, []);

  const handleJoinTournament = async (tournament) => {
    const confirmed = window.confirm(
      `Confirm payment of KES ${tournament.entryFee} to join "${tournament.name}"?`
    );

    if (!confirmed) {
      return;
    }

    setProcessingId(tournament.id);

    try {
      const result = await joinTournament(tournament.id);
      setJoinedTournaments((prev) => new Set([...prev, tournament.id]));
      setTournaments((prev) =>
        prev.map((item) => (item.id === tournament.id ? result.tournament : item))
      );
      setJoinNotice({
        type: result.matched ? 'success' : 'info',
        text: result.message,
      });
    } catch (error) {
      console.error('Error joining tournament:', error);
      setJoinNotice({
        type: 'error',
        text: error.message || 'Failed to join tournament.',
      });
    } finally {
      setProcessingId(null);
    }
  };

  const filteredTournaments =
    filter === 'all' ? tournaments : tournaments.filter((t) => t.status === filter);

  return (
    <div className="tournaments-container">
      <div className="tournaments-header">
        <h1>Live Tournaments</h1>
        <p>Join a tournament and compete for real prizes</p>
      </div>

      <div className="filter-buttons">
        <button
          className={`filter-btn ${filter === 'all' ? 'active' : ''}`}
          onClick={() => setFilter('all')}
        >
          All Tournaments
        </button>
        <button
          className={`filter-btn ${filter === 'active' ? 'active' : ''}`}
          onClick={() => setFilter('active')}
        >
          Active
        </button>
        <button
          className={`filter-btn ${filter === 'upcoming' ? 'active' : ''}`}
          onClick={() => setFilter('upcoming')}
        >
          Upcoming
        </button>
      </div>

      {joinNotice && (
        <div className={`join-notice join-notice--${joinNotice.type}`}>{joinNotice.text}</div>
      )}

      {loading ? (
        <div className="loading">Loading tournaments...</div>
      ) : (
        <div className="tournaments-grid">
          {filteredTournaments.map((tournament) => (
            <div key={tournament.id} className="tournament-card">
              <div className="tournament-badge">{tournament.image}</div>
              <h3>{tournament.name}</h3>
              <p className="tournament-description">{tournament.description}</p>

              <div className="tournament-details">
                <div className="detail">
                  <span className="label">Tournament Cost</span>
                  <span className="value">KES {Number(tournament.cost ?? tournament.entryFee).toLocaleString()}</span>
                </div>
                <div className="detail">
                  <span className="label">Prize Pool</span>
                  <span className="value">KES {tournament.prizePool.toLocaleString()}</span>
                </div>
                <div className="detail">
                  <span className="label">Players</span>
                  <span className="value">{tournament.matchSize || 2} Players</span>
                </div>
              </div>

              <div className="tournament-meta">
                <span>{tournament.duration}</span>
                <span>
                  {tournament.waitingPlayers > 0
                    ? `${tournament.waitingPlayers} player waiting`
                    : 'No opponent waiting'}
                </span>
              </div>

              <div className="tournament-participants">
                <div className="progress-bar">
                  <div
                    className="progress-fill"
                    style={{
                      width: `${((tournament.participants || 0) / (tournament.matchSize || tournament.maxParticipants || 1)) * 100}%`,
                    }}
                  ></div>
                </div>
                <span className="participant-count">
                  {tournament.participants} / {tournament.matchSize || 2} matched
                </span>
              </div>

              <button
                className={`btn ${joinedTournaments.has(tournament.id) ? 'btn-success' : 'btn-primary'}`}
                onClick={() => handleJoinTournament(tournament)}
                disabled={
                  joinedTournaments.has(tournament.id) ||
                  processingId === tournament.id ||
                  tournament.participants >= (tournament.matchSize || tournament.maxParticipants)
                }
              >
                {joinedTournaments.has(tournament.id)
                  ? 'Joined'
                  : processingId === tournament.id
                  ? 'Processing Payment...'
                  : tournament.participants >= (tournament.matchSize || tournament.maxParticipants)
                  ? 'Tournament Full'
                  : `Join Tournament - KES ${Number(tournament.cost ?? tournament.entryFee).toLocaleString()}`}
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
